data_hex="0003030 ".replace(" ","")
data=[int(data_hex[i:i+2],16) for i in range(0,len(data_hex),2)]
print("data len",len(data))
key=[0x02,0xC0,0x46,0x46,0x03,0xC0,0x06,0x06, 0x04,0xC1,0x6C,0x6C,0x05,0xC1,0x60,0x60,
0x06,0xC1,0x60,0x60,0x07,0xC1,0x06,0x06, 0x08,0xC2,0x66,0x66,0x09,0xC2,0x66,0x66,
0x0A,0xC2,0x24,0x24,0x0B,0xC2,0x66,0x66, 0x0C,0xC3,0x66,0x66,0x0D,0xC3,0x64,0x64,
0x0E,0xC3,0x60,0x60,0x0F,0xC3,0x60,0x60, 0x10,0xC4,0x66,0x66,0x11,0xC4,0x66,0x66,
0x12,0xC4,0x18,0x18,0x13,0xC4,0x0C,0x0C, 0x14,0xC5,0x6C,0x6C,0x15,0xC5,0x60,0x60,
0x16,0xC5,0x76,0x76,0x17,0xC5,0x72,0x72, 0x18,0xC6,0x66,0x66,0x19,0xC6,0x7C,0x7C,
0x1A,0xC6,0x3C,0x3C,0x1B,0xC6,0x7C,0x7C]
# extend key partially is fine; full key is 170 bytes. We'll just use what we have for alignment.
print("key len",len(key))
# odd-Y data values: data[1],data[3],...
# Try global byte-rotations r: compare data[1+2j - r? ] Actually test allows +-1 address rotate.
# best alignment: find shift s so that data[1+2j+s]==key[j]
for s in range(-6,7):
    match=0; tot=0
    for j in range(len(key)):
        idx=1+2*j+s
        if 0<=idx<len(data):
            tot+=1
            if data[idx]==key[j]: match+=1
    print(f"shift {s:+d}: {match}/{tot}")
